import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate, useNavigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import { CartProvider, useCart } from './context/CartContext';
import { api } from './services/api'; 

import Header from './components/Header';
import Login from './components/Login';
import Home from './components/Home';
import Registro from './components/Registro';
import GestionLocales from './components/GestionLocales'; 
import GestionOfertas from './components/GestionOfertas'; 
import PanelCliente from './components/PanelCliente'; 
import Carrito from './components/Carrito';
import MisPedidosCliente from './components/MisPedidosCliente';

const PrivateRoute = ({ children, roleRequired }) => {
    const { user, isAuthenticated, loading } = useAuth();
    if (loading) return null;
    if (!isAuthenticated) return <Navigate to="/login" replace />;

    const userRole = String(user?.rol || '').toLowerCase().trim();
    const required = roleRequired.toLowerCase().trim();

    if (roleRequired && userRole !== required) {
        return <Navigate to="/" replace />;
    }
    return children;
};

const AppRoutes = () => {
    const { user, isAuthenticated } = useAuth();
    const { cart, total, clearCart } = useCart();
    const navigate = useNavigate();

    const handleCheckout = async (datosEnvio) => {
        try {
            if (cart.length === 0) return;

            // CONSTRUCCIÓN DEL PEDIDO PARA MONGOOSE
            const pedidoData = {
                cliente: user?.id || user?._id, 
                local: cart[0].local?._id || cart[0].local, // Tomamos el local del primer item
                items: cart.map(item => ({
                    productoNombre: item.producto,
                    cantidad: item.cantidad,
                    precioUnitario: item.precioNuevo
                })),
                total: datosEnvio?.totalConEnvio || (total + 800),
                // IMPORTANTE: El esquema pide puntoEntrega como obligatorio
                puntoEntrega: {
                    direccion: "Entrega a domicilio", // Aquí podrías usar la dirección del user
                    lat: 0, 
                    lng: 0
                },
                estado: 'proceso'
            };

            console.log("Enviando a Backend:", pedidoData);

            const respuesta = await api.crearPedido(pedidoData); 

            if(respuesta.error) throw new Error(respuesta.error);

            alert("¡Pedido confirmado! El vendedor y el cadete han sido notificados.");
            clearCart();
            navigate('/mis-pedidos');
        } catch (error) {
            console.error("Error en handleCheckout:", error);
            alert(`Error al procesar: ${error.message}`);
        }
    };

    return (
        <>
            <Header /> 
            <Routes>
                <Route path="/" element={
                    isAuthenticated ? (
                        user?.rol === 'vendedor' ? 
                        <Navigate to="/dashboard" replace /> : 
                        <Navigate to="/panel-cliente" replace />
                    ) : (
                        <Home isLoggedIn={false} />
                    )
                } />

                <Route path="/login" element={!isAuthenticated ? <Login /> : <Navigate to="/" replace />} />
                <Route path="/registro" element={<Registro />} />

                <Route path="/dashboard" element={
                    <PrivateRoute roleRequired="vendedor">
                        <GestionLocales /> 
                    </PrivateRoute>
                } />

                <Route path="/gestion-inventario/:id" element={
                    <PrivateRoute roleRequired="vendedor">
                        <GestionOfertas /> 
                    </PrivateRoute>
                } />

                <Route path="/panel-cliente" element={
                    <PrivateRoute roleRequired="cliente">
                        <PanelCliente />
                    </PrivateRoute>
                } />

                <Route path="/carrito" element={
                    <PrivateRoute roleRequired="cliente">
                        <Carrito onCheckout={handleCheckout} />
                    </PrivateRoute>
                } />

                <Route path="/mis-pedidos" element={
                    <PrivateRoute roleRequired="cliente">
                        <MisPedidosCliente />
                    </PrivateRoute>
                } />

                <Route path="*" element={<Navigate to="/" replace />} />
            </Routes>
        </>
    );
};

function App() {
    return (
        <AuthProvider>
            <CartProvider>
                <Router>
                    <div style={{ minHeight: '100vh', background: '#f8fafc' }}>
                        <AppRoutes />
                    </div>
                </Router>
            </CartProvider>
        </AuthProvider>
    );
}

export default App;
